values.value:
[
  {
    "name": "defaultFilters",
    "type": "array",
    "required": false,
    "help": "Pre-configured filters that are always applied to the report.",
    "label": "Default Filters"
  }
]

{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "type": "object",
  "properties": {
    "defaultFilters": {
      "type": "array",
      "description": "Pre-configured filters that are always applied to the report."
    }
  }
}

{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "type": "object",
  "properties": {
    "reportId": {
      "type": "string",
      "description": "The 18-character Salesforce ID of the report to run",
      "format": "salesforce-id"
    },
    "reportDeveloperName": {
      "type": "string",
      "description": "The API/Developer Name of the report (alternative to reportId)"
    },
    "maxRows": {
      "type": "integer",
      "description": "Maximum number of rows to return (default: 200)",
      "minimum": 1,
      "maximum": 2000
    },
    "includeDetails": {
      "type": "boolean",
      "description": "Include detailed row data in response"
    },
    "filters": {
      "type": "array",
      "description": "Runtime filters to apply to the report. Each filter specifies column, operator, and value."
    }
  }
}
